export const AEON_STREAM_PNEUMA_INTERNAL = 2002 as const;
export const THOTH_GATE_TELEMETRY_FRAME_KIND =
  'thoth.gate-telemetry.v1' as const;

export const THOTH_GATE_KINDS = [
  'horoscope',
  'oath',
  'prana',
  'ki',
  'chi',
  'tai-chi',
  'mudra',
  'cognitive',
  'aura',
  'safety',
  'audio-shield',
] as const;

export type ThothGateKind = (typeof THOTH_GATE_KINDS)[number];

export interface ThothGateScore {
  gate: ThothGateKind;
  aligned: number;
  blocked: number;
  overconcentrated: number;
  underfed: number;
  readyToHandoff: number;
  perspective: string;
  theoremRef: string;
  provenance: readonly string[];
  failureResidue: string;
}

export interface ThothGateTelemetryMetrics {
  scores: readonly ThothGateScore[];
  observationWithoutIntervention: boolean;
  nonAuthoritative: boolean;
  sourceBacked: boolean;
  gateBoundariesPreserved: boolean;
}

export interface ThothGateTelemetryFrameWire {
  mediaType: {
    Abstract: typeof THOTH_GATE_TELEMETRY_FRAME_KIND;
  };
  level: number;
  phase: number;
  deficit: number;
  barcode: {
    beta1: number;
    lifespan: number;
    dilation: number;
    density: number;
  };
  data: ThothGateTelemetryMetrics;
  attributes: Record<string, string>;
  sourceId: string;
}

const perspectiveByGate: Record<ThothGateKind, string> = {
  horoscope: 'systemic-alignment',
  oath: 'stability-binding',
  prana: 'body-gate-damping',
  ki: 'preincident-defense',
  chi: 'environmental-flow',
  'tai-chi': 'moving-polarity-balance',
  mudra: 'gesture-body-gate',
  cognitive: 'system-two-handoff',
  aura: 'relational-weather',
  safety: 'policy-envelope',
  'audio-shield': 'incoming-manipulation-gate',
};

function score(
  gate: ThothGateKind,
  aligned: number,
  blocked: number,
  overconcentrated: number,
  underfed: number,
  readyToHandoff: number,
  theoremRef: string,
  provenance: readonly string[],
  failureResidue: string,
): ThothGateScore {
  return {
    gate,
    aligned,
    blocked,
    overconcentrated,
    underfed,
    readyToHandoff,
    perspective: perspectiveByGate[gate],
    theoremRef,
    provenance,
    failureResidue,
  };
}

