/**
 * Handles the gnosis thoth Gate Telemetry Total Pressure workflow.
 */
export function thothGateTelemetryTotalPressure(
  metrics: ThothGateTelemetryMetrics,
): number {
  return metrics.scores.reduce(
    (sum, gate) => sum + gate.blocked + gate.overconcentrated + gate.underfed,
    0,
  );
}

/**
 * Handles the gnosis thoth Gate Telemetry Ready Handoff Count workflow.
 */
export function thothGateTelemetryReadyHandoffCount(
  metrics: ThothGateTelemetryMetrics,
): number {
  return metrics.scores.filter((gate) => gate.readyToHandoff > 0).length;
}

/**
 * Handles the gnosis encode Thoth Gate Telemetry Frame workflow.
 */
export function encodeThothGateTelemetryFrame(
  sourceId: string,
  metrics: ThothGateTelemetryMetrics = canonicalThothGateTelemetryMetrics(),
): ThothGateTelemetryFrameWire {
  return {
    mediaType: { Abstract: THOTH_GATE_TELEMETRY_FRAME_KIND },
    level: 10,
    phase: 2,
    deficit: thothGateTelemetryTotalPressure(metrics),
    barcode: {
      beta1: Math.max(1, metrics.scores.length),
      lifespan: 1,
      dilation: 1,
      density: 1,
    },
    data: metrics,
    attributes: {
      aeon_stream_id: String(AEON_STREAM_PNEUMA_INTERNAL),
      frame_role: 'consciousness',
      thoth_frame_kind: THOTH_GATE_TELEMETRY_FRAME_KIND,
      gate_score_count: String(metrics.scores.length),
      gate_names: metrics.scores.map((gate) => gate.gate).join('|'),
      gate_total_pressure: String(thothGateTelemetryTotalPressure(metrics)),
      gate_ready_handoff_count: String(
        thothGateTelemetryReadyHandoffCount(metrics),
      ),
      observation_without_intervention: String(
        metrics.observationWithoutIntervention,
      ),
      non_authoritative: String(metrics.nonAuthoritative),
      source_backed: String(metrics.sourceBacked),
      gate_boundaries_preserved: String(metrics.gateBoundariesPreserved),
      synthetic_gnosis_admissible: 'true',
      no_source_authority_claim: 'true',
    },
    sourceId,
  };
}

/**
 * Returns whether is Thoth Gate Telemetry Frame is true.
 */
export function isThothGateTelemetryFrame(
  frame: Pick<ThothGateTelemetryFrameWire, 'mediaType' | 'attributes'>,
): boolean {
  return (
    frame.mediaType.Abstract === THOTH_GATE_TELEMETRY_FRAME_KIND &&
    frame.attributes.aeon_stream_id === String(AEON_STREAM_PNEUMA_INTERNAL)
  );
}

/**
 * Handles the gnosis render Thoth Gate Telemetry Prompt Context workflow.
 */
export function renderThothGateTelemetryPromptContext(
  metrics: ThothGateTelemetryMetrics,
): string {
  const gateRows = metrics.scores
    .map(
      (gate) =>
        `- ${gate.gate}: aligned=${gate.aligned.toFixed(2)} pressure=${(
          gate.blocked +
          gate.overconcentrated +
          gate.underfed
        ).toFixed(2)} ready=${gate.readyToHandoff.toFixed(2)} perspective=${
          gate.perspective
        } residue=${gate.failureResidue}`,
    )
    .join('\n');

  return `Thoth gate telemetry follows. Treat it as bounded observation, not authority or diagnosis.
Prompt/nudge/action contract: prompts may cite gate state; nudges may use blocked/underfed gates as next-step hints; actions must remain non-authoritative and source-backed.
Flags: observationOnly=${metrics.observationWithoutIntervention} nonAuthority=${metrics.nonAuthoritative} sourceBacked=${metrics.sourceBacked} boundariesPreserved=${metrics.gateBoundariesPreserved}
${gateRows}`;
}

/**
 * Handles the gnosis thoth Gate Telemetry Action Hint workflow.
 */
export function thothGateTelemetryActionHint(
  metrics: ThothGateTelemetryMetrics,
): string {
  const pressureGate = [...metrics.scores].sort(
    (left, right) =>
      right.blocked +
      right.overconcentrated +
      right.underfed -
      (left.blocked + left.overconcentrated + left.underfed),
  )[0];
  const handoffGates = metrics.scores
    .filter((gate) => gate.readyToHandoff > 0)
    .map((gate) => gate.gate)
    .join('|');
  return `highestPressure=${pressureGate?.gate ?? 'none'} readyHandoffs=${
    handoffGates || 'none'
  } totalPressure=${thothGateTelemetryTotalPressure(metrics).toFixed(2)}`;
}
